class Solution {
public:
    int getMaxRepetitions(string s1, int n1, string s2, int n2) {
        int max_repetitions = 0;
        int len1 = s1.length();
        int len2 = s2.length();

        for (int i = 0; i < len1; i++) {
            if (s1[i] == s2[0]) {
                max_repetitions = max(max_repetitions, n1 - i);
            }
        }

        for (int i = 0; i < len2; i++) {
            if (s2[i] == s1[0]) {
                max_repetitions = max(max_repetitions, n2 - i);
            }
        }

        return max_repetitions;
    }
};
